import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import MediaShowcaseSwiper from '../components/MediaShowcaseSwiper';
import api from '../services/api';

const BASE_URL = 'http://localhost:5000';

const Home = () => {
  const [hero, setHero] = useState(null);
  const [sliderItems, setSliderItems] = useState([]);

  useEffect(() => {
    const fetchHero = async () => {
      try {
        const { data } = await api.get('/hero');
        setHero(data);
      } catch (error) {
        console.error('Error fetching hero:', error);
        // Fallback defaults
        setHero({
          title: 'Redefining Luxury',
          subtitle: 'Discover the essentials of modern minimalism.',
          buttonText: 'Explore Collection',
          buttonLink: '/shop',
          mediaType: 'video',
          mediaUrl: ''
        });
      }
    };

    const fetchSlider = async () => {
      try {
        const { data } = await api.get('/slider');
        const mapped = data.map((item) => ({
          id: item._id,
          type: item.mediaType,
          src: `${BASE_URL}${item.mediaUrl}`,
          thumb: `${BASE_URL}${item.mediaUrl}`,
          alt: item.title,
          label: item.subtitle || '',
          caption: item.title,
        }));
        setSliderItems(mapped);
      } catch (error) {
        console.error('Error fetching slider:', error);
      }
    };

    fetchHero();
    fetchSlider();
  }, []);

  const heroMediaUrl = hero?.mediaUrl ? `${BASE_URL}${hero.mediaUrl}` : '';

  return (
    <div>
      <section className="hero" style={{ position: 'relative', overflow: 'hidden' }}>
        {hero?.mediaType === 'video' && heroMediaUrl && (
          <video
            src={heroMediaUrl}
            autoPlay
            loop
            muted
            playsInline
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              zIndex: 0,
            }}
          />
        )}
        {hero?.mediaType === 'image' && heroMediaUrl && (
          <img
            src={heroMediaUrl}
            alt={hero?.title || 'Hero'}
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              zIndex: 0,
            }}
          />
        )}
        <div
          style={{
            position: 'absolute',
            inset: 0,
            background: 'rgba(0,0,0,0.45)',
            zIndex: 1,
          }}
        />
        <div className="hero-content" style={{ position: 'relative', zIndex: 2 }}>
          <h1 className='text-5xl font-bold text-white'>{hero?.title || 'Redefining Luxury'}</h1>
          <p className='text-yellow-500 text-2xl'>{hero?.subtitle || 'Discover the essentials of modern minimalism.'}</p>
          <Link to={hero?.buttonLink || '/shop'} className="btn">
            {hero?.buttonText || 'Explore Collection'}
          </Link>
        </div>
      </section>

      <div className="container">
        <h2 className="page-title">Featured Pieces</h2>
        {sliderItems.length > 0 ? <MediaShowcaseSwiper items={sliderItems} /> : <p style={{ textAlign: 'center', color: 'var(--color-gray-dark)' }}>No featured pieces yet.</p>}
      </div>
    </div>
  );
};

export default Home;
